# RIGHT — find and remove the full pair
def safe_remove_oldest_pair(messages):
    """Remove the oldest removable message or tool pair after the system prompt."""
    i = 1
    while i < len(messages) - 1:
        if messages[i].get("role") == "assistant" and i + 1 < len(messages) - 1:
            if messages[i + 1].get("role") == "tool":
                del messages[i:i+2]   # remove assistant + tool_result together
                return messages
        del messages[i]
        return messages
    return messages

class IncrementalTokenCounter:
    """Maintains a running token total; O(1) per turn after initial load."""

    def __init__(self, enc):
        self._enc = enc
        self._total = 0
        self._counts: list[int] = []   # per-message counts, parallel to messages

    def add(self, message: dict) -> int:
        """Add a message and return the new total."""
        c = 4 + len(self._enc.encode(message.get("content") or ""))
        self._counts.append(c)
        self._total += c
        return self._total

    def remove_at(self, index: int) -> int:
        """Remove the message at `index` and return the new total."""
        self._total -= self._counts.pop(index)
        return self._total

    @property
    def total(self) -> int:
        return self._total

