def safe_summarise_or_fifo(messages, budget, summarise_fn):
    """Try summarisation; fall back to FIFO if summarise_fn raises."""
    try:
        return summarise_fn(messages)
    except Exception as exc:
        # Log the failure but do not crash the agent
        print(f"[warn] summarisation failed ({exc}); falling back to FIFO")
        return fifo_truncate(messages, budget)
